 1	import { readFileSync } from "node:fs";
 2	import pg from "pg";
 3	
 4	const cfg = JSON.parse(readFileSync(new URL("../db-config.json", import.meta.url), "utf8"));
 5	
 6	export async function withDb(fn) {
 7	  const client = new pg.Client({ host: cfg.host, port: cfg.port, user: cfg.user, password: cfg.password, database: cfg.database });
 8	  await client.connect();
 9	  await client.query('SET search_path TO "' + cfg.schema + '"');
10	  try { return await fn(client); } finally { await client.end(); }
11	}
12	export { cfg };

