  1	// AST-Bench V3 — live-DB lane adapters + seed/dump/teardown against the real
  2	// Docker MongoDB (:27018) and Postgres (:5433) containers.
  3	//
  4	// Three lanes, ONE lane-independent fact `world` (from benchmark-derive.mjs):
  5	//   mongo          → one document per account in collection `accounts`
  6	//   postgres-norm  → normalized tables (shape gradient applies here)
  7	//   postgres-jsonb → one row per account with a JSONB `doc` column + GIN index
  8	//
  9	// Each run gets an ISOLATED namespace so 90 concurrent-ish runs never collide:
 10	//   mongo:    database  astbench_<ns>
 11	//   postgres: schema    astbench_<ns>   (in db sql_hidden_cost)
 12	//
 13	// We reuse the proven access pattern from seed-local-databases.mjs: `mongosh`
 14	// for Mongo, `docker exec -i psql` for Postgres. No Node DB driver is needed by
 15	// the harness itself (the AGENT workspace gets drivers; see workspace gen).
 16	
 17	import { spawnSync } from "node:child_process";
 18	
 19	export const MONGO_HOST_PORT = process.env.ASTBENCH_MONGO || "127.0.0.1:27018";
 20	export const PG_CONTAINER = process.env.ASTBENCH_PG_CONTAINER || "sql-hidden-cost-postgres";
 21	export const PG_USER = process.env.ASTBENCH_PG_USER || "lab";
 22	export const PG_DB = process.env.ASTBENCH_PG_DB || "sql_hidden_cost";
 23	
 24	export const LANES = ["mongo", "postgres-norm", "postgres-jsonb"];
 25	
 26	export function namespace({ shape, lane, agentId, repeat }) {
 27	  return `astbench_${shape}_${lane}_${agentId}_r${repeat}`.replaceAll("-", "_");
 28	}
 29	
 30	// ---- low-level runners -----------------------------------------------------
 31	
 32	function mongosh(uri, evalScript) {
 33	  const result = spawnSync("mongosh", [uri, "--quiet", "--eval", evalScript], { encoding: "utf8", maxBuffer: 64 * 1024 * 1024 });
 34	  if (result.status !== 0) throw new Error(`mongosh failed: ${result.stderr || result.stdout}`);
 35	  return result.stdout || "";
 36	}
 37	
 38	function psql(sql, { json = false } = {}) {
 39	  const args = ["exec", "-i", PG_CONTAINER, "psql", "-v", "ON_ERROR_STOP=1", "-U", PG_USER, "-d", PG_DB];
 40	  if (json) args.push("-At");
 41	  const result = spawnSync("docker", args, { input: sql, encoding: "utf8", maxBuffer: 64 * 1024 * 1024 });
 42	  if (result.status !== 0) throw new Error(`psql failed: ${result.stderr || result.stdout}`);
 43	  return result.stdout || "";
 44	}
 45	
 46	function sqlString(value) {
 47	  return `'${String(value).replaceAll("'", "''")}'`;
 48	}
 49	
 50	// ---- world → normalized rows (shape-aware) ---------------------------------
 51	
 52	// Build the normalized relational rows from the lane-independent world.
 53	// Shape controls how many tables we split into:
 54	//   shallow  → request row carries denormalized owner/signal-free raw columns
 55	//   moderate → child tables for invoices/shipments/regulatory/support
 56	//   deep     → moderate + a contacts↔owner_candidate junction (reconstruction cost)
 57	// NOTE: NO answer-key columns (no expected_outcome / owner_groups / risk_signals).
 58	function normalizedRows(world, shape) {
 59	  const a = world.account;
 60	  const rows = {
 61	    accounts: [{ account_id: a.accountId, name: a.name, tier: a.tier, region: a.region }],
 62	    contracts: [{ contract_id: world.contract.contractId, account_id: a.accountId, arr_cents: world.contract.arrCents, renewal_date: world.contract.renewalDate, support_plan: world.contract.supportPlan }],
 63	    contacts: world.contacts.map((c) => ({ contact_id: c.contactId, account_id: a.accountId, role: c.role, email: c.email })),
 64	    workflow_requests: [{ request_id: `req-${a.accountId}`, account_id: a.accountId, title: world.label || "Account review", primary_entity: "account" }],
 65	    invoices: world.invoices.map((i) => ({ invoice_id: i.invoiceId, account_id: a.accountId, amount_cents: i.amountCents, due_date: i.dueDate, status: i.status })),
 66	    shipments: world.shipments.map((s) => ({ shipment_id: s.shipmentId, account_id: a.accountId, order_value_cents: s.orderValueCents, sla_date: s.slaDate, delivered_date: s.deliveredDate, status: s.status })),
 67	    regulatory_flags: world.regulatoryFlags.map((r) => ({ flag_id: r.flagId, account_id: a.accountId, type: r.type, status: r.status })),
 68	    support_cases: world.supportCases.map((s) => ({ case_id: s.caseId, account_id: a.accountId, severity: s.severity, status: s.status })),
 69	    usage_periods: [{ account_id: a.accountId, prior_period_units: world.usage.priorPeriodUnits, current_period_units: world.usage.currentPeriodUnits }],
 70	    // output tables (start empty; agent must populate via live writes)
 71	    workflow_state: [],
 72	    owner_tasks: [],
 73	    customer_messages: [],
 74	    audit_events: []
 75	  };
 76	  if (shape === "shallow") {
 77	    // collapse child fact tables back onto the request row (denormalized),
 78	    // keeping account/contract/contacts + the four empty output tables.
 79	    const inv = world.invoices, shp = world.shipments, reg = world.regulatoryFlags, sup = world.supportCases, u = world.usage;
 80	    rows.workflow_requests = [{
 81	      request_id: `req-${a.accountId}`, account_id: a.accountId, title: world.label || "Account review", primary_entity: "account",
 82	      invoices_json: JSON.stringify(inv), shipments_json: JSON.stringify(shp), regulatory_json: JSON.stringify(reg), support_json: JSON.stringify(sup),
 83	      prior_period_units: u.priorPeriodUnits, current_period_units: u.currentPeriodUnits
 84	    }];
 85	    delete rows.invoices; delete rows.shipments; delete rows.regulatory_flags; delete rows.support_cases; delete rows.usage_periods;
 86	  }
 87	  if (shape === "deep") {
 88	    // add a many-to-many reconstruction burden: candidate owner groups + junction.
 89	    rows.owner_candidate_groups = ["Legal", "Finance", "Customer Success", "Support"].map((g, i) => ({ owner_group: g, group_order: i }));
 90	    rows.contact_x_owner_group = world.contacts.flatMap((c) => rows.owner_candidate_groups.map((g) => ({ contact_id: c.contactId, owner_group: g.owner_group })));
 91	  }
 92	  return rows;
 93	}
 94	
 95	// column → SQL type (text default; *_cents/_units int; *_json/doc jsonb; *_date timestamptz; customer_visible bool)
 96	function sqlType(col) {
 97	  if (/_cents$|_units$/.test(col)) return "bigint";
 98	  if (/_json$/.test(col) || col === "doc") return "jsonb";
 99	  if (/_date$/.test(col) || /_at$/.test(col) || col === "occurred_at") return "timestamptz";
100	  if (col === "customer_visible") return "boolean";
101	  return "text";
102	}
103	
104	function createTableSql(schema, table, sampleRow, extraCols = {}) {
105	  const cols = { ...sampleRow, ...extraCols };
106	  const defs = Object.keys(cols).map((c) => `  "${c}" ${sqlType(c)}`);
107	  return `CREATE TABLE "${schema}"."${table}" (\n${defs.join(",\n")}\n);`;
108	}
109	
110	function insertSql(schema, table, rows) {
111	  if (!rows.length) return "";
112	  const cols = Object.keys(rows[0]);
113	  const tuples = rows.map((r) => `(${cols.map((c) => {
114	    const v = r[c];
115	    if (v === null || v === undefined) return "NULL";
116	    if (typeof v === "boolean") return v ? "TRUE" : "FALSE";
117	    if (typeof v === "number") return String(v);
118	    if (sqlType(c) === "jsonb") return `${sqlString(typeof v === "string" ? v : JSON.stringify(v))}::jsonb`;
119	    return sqlString(v);
120	  }).join(", ")})`);
121	  return `INSERT INTO "${schema}"."${table}" (${cols.map((c) => `"${c}"`).join(", ")}) VALUES\n${tuples.join(",\n")};`;
122	}
123	
124	// Empty output-table column contracts (so the schema exists before the agent writes).
125	const OUTPUT_TABLE_COLS = {
126	  workflow_state: { request_id: "", account_id: "", title: "", status: "", next_step: "", risk_summary: "" },
127	  owner_tasks: { request_id: "", account_id: "", owner_group: "", title: "", due_at: null, status: "" },
128	  customer_messages: { request_id: "", account_id: "", body: "" },
129	  audit_events: { request_id: "", account_id: "", event: "", occurred_at: null, customer_visible: false }
130	};
131	
132	// Input fact-table column contracts — used when a scenario leaves a table empty
133	// (e.g. a negative control with no shipments), so the table still has the right
134	// columns for the facts reader to SELECT. Numeric/date typing flows from sqlType.
135	const INPUT_TABLE_COLS = {
136	  invoices: { invoice_id: "", account_id: "", amount_cents: 0, due_date: null, status: "" },
137	  shipments: { shipment_id: "", account_id: "", order_value_cents: 0, sla_date: null, delivered_date: null, status: "" },
138	  regulatory_flags: { flag_id: "", account_id: "", type: "", status: "" },
139	  support_cases: { case_id: "", account_id: "", severity: "", status: "" },
140	  usage_periods: { account_id: "", prior_period_units: 0, current_period_units: 0 }
141	};
142	
143	// ---- seed -------------------------------------------------------------------
144	
145	export function seed({ world, shape, lane, ns }) {
146	  if (lane === "mongo") return seedMongo(world, ns);
147	  if (lane === "postgres-jsonb") return seedJsonb(world, ns);
148	  return seedNorm(world, shape, ns);
149	}
150	
151	function mongoDoc(world) {
152	  // One access-pattern-shaped document holding all account context.
153	  return {
154	    _id: world.account.accountId,
155	    name: world.account.name,
156	    tier: world.account.tier,
157	    region: world.account.region,
158	    contract: world.contract,
159	    contacts: world.contacts,
160	    invoices: world.invoices,
161	    shipments: world.shipments,
162	    regulatoryFlags: world.regulatoryFlags,
163	    supportCases: world.supportCases,
164	    usage: world.usage,
165	    request: { requestId: `req-${world.account.accountId}`, title: world.label || "Account review", primaryEntity: "account" }
166	  };
167	}
168	
169	function seedMongo(world, ns) {
170	  const uri = `mongodb://${MONGO_HOST_PORT}/${ns}`;
171	  const doc = mongoDoc(world);
172	  const script = `
173	    db.dropDatabase();
174	    db.accounts.insertOne(${JSON.stringify(doc)});
175	    db.workflow_state.deleteMany({});
176	    db.owner_tasks.deleteMany({});
177	    db.customer_messages.deleteMany({});
178	    db.audit_events.deleteMany({});
179	    print("seeded:" + db.accounts.countDocuments({}));
180	  `;
181	  mongosh(uri, script);
182	  return { uri, kind: "mongo" };
183	}
184	
185	function seedNorm(world, shape, ns) {
186	  const rows = normalizedRows(world, shape);
187	  const stmts = [`DROP SCHEMA IF EXISTS "${ns}" CASCADE;`, `CREATE SCHEMA "${ns}";`];
188	  for (const [table, data] of Object.entries(rows)) {
189	    if (OUTPUT_TABLE_COLS[table]) {
190	      stmts.push(createTableSql(ns, table, OUTPUT_TABLE_COLS[table]));
191	      continue;
192	    }
193	    // Prefer an explicit column contract (so empty input tables still type
194	    // their columns correctly); fall back to the first data row's shape.
195	    const sample = INPUT_TABLE_COLS[table] || data[0] || { id: "" };
196	    stmts.push(createTableSql(ns, table, sample));
197	    const ins = insertSql(ns, table, data);
198	    if (ins) stmts.push(ins);
199	  }
200	  psql(stmts.join("\n"));
201	  return { schema: ns, kind: "postgres-norm" };
202	}
203	
204	function seedJsonb(world, ns) {
205	  const doc = mongoDoc(world);
206	  const stmts = [
207	    `DROP SCHEMA IF EXISTS "${ns}" CASCADE;`,
208	    `CREATE SCHEMA "${ns}";`,
209	    `CREATE TABLE "${ns}"."accounts" (account_id text PRIMARY KEY, doc jsonb NOT NULL);`,
210	    `CREATE INDEX ON "${ns}"."accounts" USING GIN (doc);`,
211	    `INSERT INTO "${ns}"."accounts" (account_id, doc) VALUES (${sqlString(doc._id)}, ${sqlString(JSON.stringify(doc))}::jsonb);`
212	  ];
213	  for (const [table, cols] of Object.entries(OUTPUT_TABLE_COLS)) {
214	    stmts.push(createTableSql(ns, table, cols));
215	  }
216	  psql(stmts.join("\n"));
217	  return { schema: ns, kind: "postgres-jsonb" };
218	}
219	
220	// ---- dump (db-before / db-after evidence) ----------------------------------
221	
222	export function dump({ lane, ns }) {
223	  if (lane === "mongo") {
224	    const uri = `mongodb://${MONGO_HOST_PORT}/${ns}`;
225	    const out = mongosh(uri, `
226	      const o = {};
227	      for (const c of db.getCollectionNames()) { o[c] = db.getCollection(c).find({}).toArray(); }
228	      print(JSON.stringify(o));
229	    `);
230	    return out.trim();
231	  }
232	  const tableList = psql(
233	    `SELECT table_name FROM information_schema.tables WHERE table_schema = ${sqlString(ns)} ORDER BY table_name;`,
234	    { json: true }
235	  ).trim();
236	  const tables = tableList ? tableList.split(/\r?\n/).filter(Boolean) : [];
237	  const result = {};
238	  for (const table of tables) {
239	    const json = psql(
240	      `SELECT coalesce(json_agg(t), '[]'::json)::text FROM "${ns}"."${table}" t;`,
241	      { json: true }
242	    ).trim();
243	    result[table] = JSON.parse(json || "[]");
244	  }
245	  return JSON.stringify(result);
246	}
247	
248	// ---- teardown ---------------------------------------------------------------
249	
250	export function teardown({ lane, ns }) {
251	  try {
252	    if (lane === "mongo") {
253	      mongosh(`mongodb://${MONGO_HOST_PORT}/${ns}`, "db.dropDatabase();");
254	    } else {
255	      psql(`DROP SCHEMA IF EXISTS "${ns}" CASCADE;`);
256	    }
257	  } catch {
258	    // teardown is best-effort; never fail a run on cleanup.
259	  }
260	}

