  3	const RULES = {
  4	  invoiceHighCents: 2_500_000,
  5	  usageDropFraction: 0.3,
  6	  qualifyingTiers: ["strategic", "enterprise"],
  7	  highSupportSeverities: ["high", "critical"],
  8	  escalationStatus: "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  9	  monitorStatus: "Monitoring — no escalation required."
 10	};
 11	
 12	const OWNER_FOR_CATEGORY = {
 13	  regulatory: "Legal",
 14	  invoice: "Finance",
 15	  shipment: "Customer Success",
 16	  usage: "Customer Success",
 17	  support: "Support"
 18	};
 19	
 20	const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
 21	const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
 22	const SIGNAL_NAME = {
 23	  regulatory: "Regulatory hold",
 24	  invoice: "Overdue invoice",
 25	  shipment: "Delayed shipment",
 26	  support: "Escalated support",
 27	  usage: "Usage decline"
 28	};
