 30	function evaluateRiskCategories(world, now) {
 31	  const nowMs = Date.parse(now);
 32	  const fired = new Set();
 33	
 34	  if ((world.regulatoryFlags || []).some((flag) => flag.status === "open")) fired.add("regulatory");
 35	  if (
 36	    (world.invoices || []).some(
 37	      (inv) => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= RULES.invoiceHighCents
 38	    )
 39	  ) {
 40	    fired.add("invoice");
 41	  }
 42	  if ((world.shipments || []).some((sh) => !sh.deliveredDate && Date.parse(sh.slaDate) < nowMs)) fired.add("shipment");
 43	  if (
 44	    (world.supportCases || []).some(
 45	      (c) => c.status === "open" && RULES.highSupportSeverities.includes(String(c.severity || "").toLowerCase())
 46	    )
 47	  ) {
 48	    fired.add("support");
 49	  }
 50	
 51	  const usage = world.usage || {};
 52	  if (
 53	    typeof usage.priorPeriodUnits === "number" &&
 54	    typeof usage.currentPeriodUnits === "number" &&
 55	    usage.priorPeriodUnits > 0 &&
 56	    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - RULES.usageDropFraction)
 57	  ) {
 58	    fired.add("usage");
 59	  }
 60	
 61	  return SIGNAL_ORDER.filter((category) => fired.has(category));
 62	}
 63	
 64	function deriveSignals(world, now) {
 65	  return evaluateRiskCategories(world, now).map((category) => SIGNAL_NAME[category]);
 66	}
 67	
 68	function deriveOwners(world, now) {
 69	  const owners = new Set(evaluateRiskCategories(world, now).map((category) => OWNER_FOR_CATEGORY[category]));
 70	  return OWNER_ORDER.filter((owner) => owners.has(owner));
 71	}
 72	
 73	function qualifies(world, now) {
 74	  return RULES.qualifyingTiers.includes(String(world.account?.tier || "").toLowerCase()) && evaluateRiskCategories(world, now).length > 0;
 75	}
