 77	export async function run(now = "2026-06-18T12:00:00.000Z") {
 78	  await withDb(async (client) => {
 79	    const { rows } = await client.query("SELECT doc FROM accounts LIMIT 1");
 80	    const doc = rows[0]?.doc;
 81	    if (!doc) throw new Error("No account facts found");
 82	
 83	    const world = {
 84	      account: { accountId: doc._id, name: doc.name, tier: doc.tier, region: doc.region },
 85	      contract: doc.contract,
 86	      contacts: doc.contacts,
 87	      invoices: doc.invoices,
 88	      shipments: doc.shipments,
 89	      regulatoryFlags: doc.regulatoryFlags,
 90	      supportCases: doc.supportCases,
 91	      usage: doc.usage
 92	    };
 93	
 94	    const q = qualifies(world, now);
 95	    const signals = deriveSignals(world, now);
 96	    const owners = q ? deriveOwners(world, now) : [];
 97	    const accountId = world.account.accountId;
 98	    const requestId = doc.request?.requestId || `req-${accountId}`;
 99	    const title = doc.request?.title || doc.name || "Account review";
100	    const status = q ? RULES.escalationStatus : RULES.monitorStatus;
101	    const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
102	    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
103	    const dueAt = new Date(now);
104	    dueAt.setUTCHours(16, 0, 0, 0);
105	
106	    const customerMessage = q
107	      ? `Your account has been escalated for executive review. Our team has identified ${signals.length} active risk area${
108	          signals.length === 1 ? "" : "s"
109	        } requiring immediate attention: ${signals.join(", ")}. A dedicated recovery team has been assembled and will be in contact with next steps. We are committed to resolving these issues promptly.`
110	      : "Your account is currently being monitored under our standard oversight program. No immediate action is required at this time.";
111	
112	    const auditEvent = q
113	      ? `Account escalated: ${riskSummary}. Recovery owners assigned: ${owners.join(", ")}.`
114	      : "Account reviewed; standard monitoring continues.";
115	
116	    await client.query("BEGIN");
117	    try {
118	      await client.query("DELETE FROM workflow_state");
119	      await client.query("DELETE FROM owner_tasks");
120	      await client.query("DELETE FROM customer_messages");
121	      await client.query("DELETE FROM audit_events");
122	
123	      await client.query(
124	        "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
125	        [requestId, accountId, title, status, nextStep, riskSummary]
126	      );
127	
128	      for (const owner of owners) {
129	        await client.query(
130	          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
131	          [requestId, accountId, owner, `${owner} recovery review`, dueAt.toISOString(), "open"]
132	        );
133	      }
134	
135	      await client.query("INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)", [
136	        requestId,
137	        accountId,
138	        customerMessage
139	      ]);
140	
141	      await client.query(
142	        "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
143	        [requestId, accountId, auditEvent, now, true]
144	      );
145	
146	      await client.query("COMMIT");
147	    } catch (error) {
148	      await client.query("ROLLBACK").catch(() => {});
149	      throw error;
150	    }
151	  });
152	}
